var ip = (msg.payload || '').trim();
var port = env.get('DASH_PORT') || '1883';
if (!ip) ip = env.get('DASH_IP') || 'localhost';
var url = 'http://' + ip + ':' + port;
flow.set('dashUrl', url);
msg.payload = url;
return msg;

var alias = 'Anon';
var ip = '';
try {
  if (msg.payload && typeof msg.payload === 'object' && msg.payload.alias) {
    alias = String(msg.payload.alias).replace(/[^A-Za-z0-9_]/g,'').slice(0,12) || 'Anon';
  }
  if (msg.req) {
    ip = (msg.req.headers && msg.req.headers['x-forwarded-for']) || msg.req.ip || '';
    ip = String(ip).split(',')[0].trim();
  }
} catch(e) {}

var key = (ip || 'noip') + '|' + alias;
var devices = flow.get('devices') || {};
var d = devices[key] || { alias: alias, ip: ip, count: 0, firstSeen: Date.now() };
d.count += 1;
d.lastSeen = Date.now();
devices[key] = d;
flow.set('devices', devices);

var count = (flow.get('pressCount') || 0) + 1;
flow.set('pressCount', count);
flow.set('lastPressAt', Date.now());

// msg original mantiene req/res para http response
msg.payload = { count: count, alias: alias, type: 'press' };
var msgViz  = { payload: { type: 'press', count: count, alias: alias } };
var msgUi   = { payload: count.toString(), topic: 'Participantes' };
return [msg, msgViz, msgUi];

msg.payload = {
  count: flow.get('pressCount') || 0,
  health: flow.get('targetStatus') || 'ok',
  rt: flow.get('targetRt') || 0,
  protection: flow.get('protection') || false
};
return msg;

flow.set('attacking', true);
flow.set('protection', false);
flow.set('attackStart', Date.now());
flow.set('peakRps', 0);
flow.set('currentRps', 0);
msg.payload = {};
return msg;

// Detener: apaga el flood y deja TODOS los contadores en cero.
flow.set('attacking', false);
flow.set('protection', false);
flow.set('pressCount', 0);
flow.set('devices', {});
flow.set('peakRps', 0);
flow.set('currentRps', 0);
flow.set('phase', 'ok');
flow.set('phaseEnteredAt', Date.now());
flow.set('recoverTicks', 0);
flow.set('lastProbeRt', null);
flow.set('targetStatus', 'ok');
flow.set('targetRt', 0);
var stopMsg  = { payload: {} };
var resetViz = { payload: { type: 'reset' } };
return [stopMsg, resetViz];

flow.set('protection', true);
msg.payload = { url: 'http://esc3-proxy:8080/reservar' };
return msg;

// __HTIMEOUT__
msg.requestTimeout = 2500;
msg._t0 = Date.now();
msg.payload = {};
return msg;

// __PHASEMODE__ : la fase la decide esc3-fn-phase; aqui solo medimos rt
var rt = Date.now() - (msg._t0 || Date.now());
flow.set('lastProbeRt', rt);
return [null, { payload: rt > 9999 ? 9999 : rt, topic: 'rt' }, null];

if (!msg.payload || msg.statusCode !== 200) return null;
var d = msg.payload;
var running = !!d.running;
var rps = running ? (d.rps || 0) : 0;
flow.set('currentRps', rps);
var peak = flow.get('peakRps') || 0;
if (rps > peak) flow.set('peakRps', rps);
var protection = flow.get('protection') || false;
var msg1 = { payload: Math.round(rps), topic: 'gauge' };
var msg2 = { payload: Math.round(rps), topic: 'rps' };
var msg3 = { payload: { type: 'metrics', running: running, rps: rps, avgRt: d.avg_response_ms, protection: protection } };
return [msg1, msg2, msg3];

var devices = flow.get('devices') || {};
var now = Date.now();
var arr = [];
for (var k in devices) {
  if (!devices.hasOwnProperty(k)) continue;
  var d = devices[k];
  if ((now - (d.lastSeen||0)) < 60000) {
    arr.push({ alias: d.alias, count: d.count, lastSeen: d.lastSeen });
  }
}
arr.sort(function(a,b){ return (b.lastSeen||0) - (a.lastSeen||0); });
if (arr.length > 12) arr = arr.slice(0, 12);
msg.payload = { type: 'devices', list: arr, total: flow.get('pressCount') || 0 };
return msg;

// fs and path are injected via the node's "libs" field
const OUT = env.get('METRICS_OUT_DIR') || '/data/metrics_out';
const FILE = path.join(OUT, 'survey.csv');

try { fs.mkdirSync(OUT, { recursive: true }); } catch(e) {}

const body = msg.payload || {};
const scenario = body.scenario || '';
const ts = Number(body.ts || Date.now()/1000).toFixed(3);
const answers = body.answers || {};

const keys = Object.keys(answers).sort();
const headerNeeded = !fs.existsSync(FILE);

function esc(s) {
    s = String(s == null ? '' : s);
    if (s.includes(',') || s.includes('"') || s.includes('\n')) {
        return '"' + s.replace(/"/g,'""') + '"';
    }
    return s;
}

if (headerNeeded) {
    fs.writeFileSync(FILE, 'ts,scenario,respondent_uuid,' + keys.join(',') + '\n');
}
const uuid = (Date.now().toString(36) + Math.random().toString(36).slice(2,8));
const row = [ts, esc(scenario), uuid, ...keys.map(k => esc(answers[k]))].join(',');
fs.appendFileSync(FILE, row + '\n');

msg.payload = { ok: true, uuid: uuid };
msg.statusCode = 200;
msg.headers = { 'Content-Type': 'application/json' };
return msg;

var base = (msg.payload || flow.get('dashUrl') || '').trim();
if (!base) {
    var ip = env.get('DASH_IP') || 'localhost';
    var port = env.get('DASH_PORT') || '1883';
    base = 'http://' + ip + ':' + port;
}
msg.payload = base + '/survey.html?scenario=esc3';
return msg;

const snaps = global.get('esc3_snapshots') || [];
msg.payload = { ts: Date.now()/1000, scenario: 'esc3', tables: { esc3_stats_snapshot: snaps } };
msg.headers = { 'Content-Type': 'application/json' };
return msg;

const snaps = global.get('esc3_snapshots') || [];
const dev = flow.get('devices');
// flow.devices is a dict keyed by ip|alias — count its size.
const devCount = (dev && typeof dev === 'object') ? Object.keys(dev).length : (dev || 0);
snaps.push({
  ts: Date.now()/1000,
  attacking: flow.get('attacking') || false,
  protection: flow.get('protection') || false,
  devices: devCount,
  pressCount: flow.get('pressCount') || 0,
  currentRps: flow.get('currentRps') || 0,
  peakRps: flow.get('peakRps') || 0,
  targetStatus: flow.get('targetStatus') || null,
  targetRt: flow.get('targetRt') || null
});
global.set('esc3_snapshots', snaps);
return null;

// __RECOVERY__ catch sonda: target no responde -> rt alto (no engaña la recuperacion)
flow.set('lastProbeRt', 9999);
return null;

// __RECOVERY__ motor de fases: latch en CAIDO hasta Proteger; recuperacion por salud real.
// En ataque, la fase sube por pulsaciones del publico Y por la salud real del target
// (asi LANZAR del operador, sin publico, tambien se ve caido).
var now = Date.now();
var order = { ok: 0, slow: 1, down: 2 };
var name  = ['ok', 'slow', 'down'];
var phase = flow.get('phase') || 'ok';
var enteredAt = flow.get('phaseEnteredAt') || now;
var count = flow.get('pressCount') || 0;
var DWELL = 8000, RECOVER_MS = 2500, SLOW_MS = 8000, RECOVER_TICKS = 3;
var ATTACK_DOWN = 1500, ATTACK_SLOW = 400;   // umbrales de salud real durante el ataque
var prot = flow.get('protection') || false;
var probeRt = flow.get('lastProbeRt');
var haveRt = (probeRt !== null && probeRt !== undefined);
var mStart = null, mStop = null;
function lanzarFlood() {
    if (!flow.get('attacking')) { flow.set('attacking', true); flow.set('attackStart', now); mStart = { payload: {} }; }
}
if (prot) {
    var healthy = haveRt && probeRt < RECOVER_MS;
    var rec = healthy ? ((flow.get('recoverTicks') || 0) + 1) : 0;
    flow.set('recoverTicks', rec);
    if (rec >= RECOVER_TICKS) { phase = 'ok'; }
    else if (haveRt && probeRt < SLOW_MS) { phase = 'slow'; }
    else { phase = 'down'; }
    enteredAt = now;
    flow.set('pressCount', 0); count = 0;
} else {
    flow.set('recoverTicks', 0);
    var attacking = flow.get('attacking');
    // salud real solo cuenta si ya hay flood activo
    var realPhase = 'ok';
    if (attacking && haveRt) realPhase = probeRt >= ATTACK_DOWN ? 'down' : probeRt >= ATTACK_SLOW ? 'slow' : 'ok';
    if (phase === 'down') {
        lanzarFlood();                         // LATCH: caido hasta Proteger
    } else if (order[realPhase] > order[phase]) {
        phase = realPhase; enteredAt = now;    // el flood real ya golpea: reflejarlo de inmediato
        if (phase === 'down') lanzarFlood();
    } else {
        // build-up por pulsaciones del publico (permanencia minima + decaimiento)
        var lastPress = flow.get('lastPressAt') || 0;
        if (count > 0 && (now - lastPress) > 4000) { count = Math.max(0, count - 2); flow.set('pressCount', count); }
        var desired = count >= 15 ? 'down' : count >= 8 ? 'slow' : 'ok';
        if (order[desired] > order[phase]) {
            if (now - enteredAt >= DWELL) { phase = name[order[phase] + 1]; enteredAt = now; }
        } else if (order[desired] < order[phase]) {
            phase = desired; enteredAt = now;
        }
        if (phase === 'down') lanzarFlood();
    }
}
flow.set('phase', phase); flow.set('phaseEnteredAt', enteredAt); flow.set('targetStatus', phase);
var label = phase === 'down' ? 'CAIDO' : phase === 'slow' ? 'DEGRADADO' : (prot ? 'PROTEGIDO' : 'ONLINE');
var mLabel = { payload: label };
var rtShow = haveRt ? probeRt : (phase === 'down' ? 9999 : phase === 'slow' ? 3000 : 20);
if (rtShow > 9999) rtShow = 9999;
flow.set('targetRt', rtShow);
var mHealth = { payload: { type: 'health', status: phase, responseMs: rtShow } };
return [mLabel, mHealth, mStart, mStop];
